import{_ as o,o as r,c as t,a5 as a}from"./chunks/framework.CW28V7p_.js";const c=JSON.parse('{"title":"Glossary","description":"","frontmatter":{},"headers":[],"relativePath":"glossary.md","filePath":"glossary.md","lastUpdated":1780937944000}'),s={name:"glossary.md"};function n(l,e,i,d,u,p){return r(),t("div",null,[...e[0]||(e[0]=[a('<h1 id="glossary" tabindex="-1">Glossary <a class="header-anchor" href="#glossary" aria-label="Permalink to &quot;Glossary&quot;">​</a></h1><p>Накопичувальний словник усіх термінів курсу. Сортовано алфавітом (англ.). Кожен term має посилання на module де deeper explanation.</p><h2 id="a" tabindex="-1">A <a class="header-anchor" href="#a" aria-label="Permalink to &quot;A&quot;">​</a></h2><p><strong>Account</strong> — основна абстракція state на Solana. 5 fields: lamports, owner, data, executable, rent_epoch. Identify by Pubkey. <a href="/module-2/1-account-basics">Module 2.1</a></p><p><strong>AccountsDB</strong> — validator&#39;s storage всіх accounts state. Mainnet ~500GB on NVMe + RAM cache. Alpenglow на tmpfs (RAM). <a href="/module-6/3-accountsdb">Module 6.3</a></p><p><strong>Account lock</strong> — Sealevel scheduler tracks which TXs touch which accounts. Writable accounts exclusive, read-only shared. <a href="/module-6/4-stages">Module 6.4</a></p><p><strong>Activation epoch</strong> — epoch коли feature flag активується. До неї old behavior, після — new. <a href="/module-4/7-recent-simds">Module 4.7</a></p><p><strong>Active stake</strong> — SOL delegated до validators які зараз голосують (non-delinquent). <a href="/module-1/5-validator-status">Module 1.5</a></p><p><strong>Address Lookup Table (ALT)</strong> — on-chain account containing list pubkeys. TX references via 1-byte index замість 32-byte pubkey. Дозволяє 256+ accounts у TX. <a href="/module-3/5-versioned-tx-alts">Module 3.5</a></p><p><strong>Alertmanager</strong> — Prometheus component для notifications. Maps alerts до channels (Slack, Telegram, PagerDuty). <a href="/module-8/8-monitoring-stack">Module 8.8</a></p><p><strong>Alpenglow</strong> — proposed next-gen Solana consensus protocol (SIMD-0326). BLS aggregated signatures, faster finality. Currently тестується community cluster. <a href="/module-4/4-alpenglow">Module 4.4</a></p><p><strong>Anchor</strong> — popular Rust framework для writing Solana smart contracts. <a href="/module-2/2-programs">Module 2.2</a></p><p><strong>Atomicity</strong> — TX execute як єдиний unit: усі instructions success або жодна. Foundation of DeFi composability. <a href="/module-3/1-tx-anatomy">Module 3.1</a></p><p><strong>ATA (Associated Token Account)</strong> — deterministic token account для пари <code>(owner_wallet, token_mint)</code>. Auto-derived, standard convention. <a href="/module-2/4-tokens-ata">Module 2.4</a></p><p><strong>Authorized voter</strong> — key що signs vote TXs. Hot key OK (на сервері). <a href="/module-4/3-votes-credits">Module 4.3</a></p><p><strong>Authorized withdrawer</strong> — controls vote account: withdraw, change authorities, set commission. <strong>Critical key</strong> — cold storage mandatory mainnet. <a href="/module-4/3-votes-credits">Module 4.3</a></p><p><strong>AVX-512</strong> — Intel CPU SIMD instruction set. Firedancer uses для accelerated sigverify. <a href="/module-6/5-firedancer">Module 6.5</a></p><h2 id="b" tabindex="-1">B <a class="header-anchor" href="#b" aria-label="Permalink to &quot;B&quot;">​</a></h2><p><strong>Backup</strong> — copy critical data (keypairs, configs) у safe locations. Mandatory before destructive operations. <a href="/module-8/2-backups">Module 8.2</a></p><p><strong>BAM (Block Assembly Marketplace)</strong> — Jito&#39;s permissioned block-building marketplace. Eligible validators receive bundles + tips. <a href="/module-7/3-mev-jito">Module 7.3</a></p><p><strong>Bank</strong> — internal термін для in-progress block state у validator memory. <a href="/module-1/4-block-production">Module 1.4</a></p><p><strong>Banking stage</strong> — leader mode component що executes TXs у parallel via Sealevel. <a href="/module-6/4-stages">Module 6.4</a></p><p><strong>Base fee</strong> — 5000 lamports per signature. 50% burned, 50% leader. <a href="/module-3/3-fees">Module 3.3</a></p><p><strong>Base58</strong> — encoding для Solana pubkeys (легше читати ніж hex). <a href="/module-2/1-account-basics">Module 2.1</a></p><p><strong>Binary</strong> — виконуваний файл, результат компіляції source code. ELF format на Linux. <a href="/module-0/1-build">Module 0.1</a></p><p><strong>Block</strong> — data container що зберігає всі TXs виконані у конкретному slot. <a href="/module-1/2-slots-epochs">Module 1.2</a></p><p><strong>Block engine</strong> — Jito component що simulates blocks з bundles, picks best paying. <a href="/module-7/3-mev-jito">Module 7.3</a></p><p><strong>Block height</strong> — кількість blocks створених від genesis (виключає skipped slots). <a href="/module-1/2-slots-epochs">Module 1.2</a></p><p><strong>Blockhash</strong> — унікальний відбиток block content. Використовується у TX як &quot;recent blockhash&quot; для expiry tracking. <a href="/module-1/2-slots-epochs">Module 1.2</a></p><p><strong>Blockhash expiry</strong> — TX has ~150 slots (~60 sec) щоб бути included. <a href="/module-3/4-lifecycle">Module 3.4</a></p><p><strong>BLS signature</strong> — Boneh-Lynn-Shacham signature scheme. Дозволяє aggregation (many signers → one signature). Alpenglow uses. <a href="/module-4/4-alpenglow">Module 4.4</a></p><p><strong>Bootstrap validator</strong> — initial validator(s) у genesis. Define cluster&#39;s starting point. <a href="/module-1/6-genesis">Module 1.6</a></p><p><strong>Borsh</strong> — binary serialization format used by Solana programs. <a href="/module-3/2-instructions">Module 3.2</a></p><p><strong>BPF Loader</strong> — native program що loads + executes BPF programs. Current = BPF Loader Upgradeable. <a href="/module-2/2-programs">Module 2.2</a></p><p><strong>BPF program</strong> — user-deployed smart contract. Compiled до BPF bytecode, executes у sandboxed BPF VM. <a href="/module-2/2-programs">Module 2.2</a></p><p><strong>Branch (git)</strong> — рухомий покажчик на commit. Просувається з новими commits. <a href="/module-0/2-git">Module 0.2</a></p><p><strong>Bump seed</strong> — 0-255 value used у PDA derivation щоб find off-curve address. <a href="/module-2/5-pda-deep">Module 2.5</a></p><p><strong>Bundle (Jito)</strong> — group of TXs that execute together, submitted by searcher з tip. <a href="/module-7/3-mev-jito">Module 7.3</a></p><p><strong>Bytecode</strong> — compiled program format (BPF) що executes у BPF VM. <a href="/module-2/2-programs">Module 2.2</a></p><h2 id="c" tabindex="-1">C <a class="header-anchor" href="#c" aria-label="Permalink to &quot;C&quot;">​</a></h2><p><strong>Cargo</strong> — Rust&#39;s build tool + package manager. Manages deps, compiles, installs. <a href="/module-0/3-cargo">Module 0.3</a></p><p><strong>Cargo.lock</strong> — exact dependency versions snapshot для reproducible builds. <a href="/module-0/3-cargo">Module 0.3</a></p><p><strong>Cargo.toml</strong> — Rust project manifest. <a href="/module-0/3-cargo">Module 0.3</a></p><p><strong>CARGO_INSTALL_ROOT</strong> — env variable specifying default install location. <a href="/module-0/3-cargo">Module 0.3</a></p><p><strong>Catch-up</strong> — validator&#39;s process recovering missed slots/blocks через repair protocol. <a href="/module-5/4-repair">Module 5.4</a></p><p><strong>Checkout (git)</strong> — switch між commits/branches/tags. <a href="/module-0/2-git">Module 0.2</a></p><p><strong>Client diversity</strong> — multiple validator implementations (agave + Firedancer) для network resilience. <a href="/module-6/5-firedancer">Module 6.5</a></p><p><strong>Cluster</strong> — група validators + RPC nodes що утворюють одну Solana network. <a href="/module-1/1-cluster">Module 1.1</a></p><p><strong>Cluster membership</strong> — list of all visible nodes у cluster, maintained через gossip. <a href="/module-5/1-gossip">Module 5.1</a></p><p><strong>cNFT (compressed NFT)</strong> — NFT з state compression. ~1000x cheaper ніж standard. Uses Merkle trees. <a href="/module-10/6-compression-nfts">Module 10.6</a></p><p><strong>Coding shred</strong> — Reed-Solomon parity shred для erasure recovery. <a href="/module-5/3-shreds">Module 5.3</a></p><p><strong>Co-location</strong> — physically placing servers у tier-1 datacenter (Equinix). Critical для validator network latency. <a href="/module-8/5-hardware-specs">Module 8.5</a></p><p><strong>Cold key</strong> — key stored offline. Rarely used. Для high-value operations (withdrawer authority). <a href="/module-8/1-keypair-security">Module 8.1</a></p><p><strong>Commission</strong> — % validator rewards operator takes (0-100%). <a href="/module-4/3-votes-credits">Module 4.3</a></p><p><strong>Commission bps</strong> — commission set у basis points (800 = 8%). Jito-Solana flag. <a href="/module-7/5-jito-block-engine">Module 7.5</a></p><p><strong>Commit (git)</strong> — snapshot стану repository у момент. SHA-1 hash, parent, message, author. <a href="/module-0/2-git">Module 0.2</a></p><p><strong>Compaction</strong> — periodic AccountsDB cleanup що merges write logs. <a href="/module-6/3-accountsdb">Module 6.3</a></p><p><strong>Compiler</strong> — translator з source code (Rust) до machine code (binary). <a href="/module-0/1-build">Module 0.1</a></p><p><strong>Compressed NFT (cNFT)</strong> — see <a href="/glossary#c"><code>cNFT</code></a>. <a href="/module-10/6-compression-nfts">Module 10.6</a></p><p><strong>Compute Budget Program</strong> — native program для controlling per-TX compute limits + priority fees. <a href="/module-3/3-fees">Module 3.3</a></p><p><strong>Compute Unit (CU)</strong> — measure of operations у TX. Default budget 200,000 per TX. <a href="/module-3/2-instructions">Module 3.2</a></p><p><strong>Confidence interval</strong> — uncertainty range provided з oracle price. <a href="/module-10/7-oracles">Module 10.7</a></p><p><strong>Confidential transfers</strong> — Token-2022 extension hiding transfer amounts через zero-knowledge. <a href="/module-2/6-token-2022">Module 2.6</a></p><p><strong>Confirmed (slot/TX)</strong> — ≥2/3 stake voted за block. Probabilistic finality. ~1-3 sec mainnet. <a href="/module-3/4-lifecycle">Module 3.4</a></p><p><strong>ContactInfo</strong> — gossip-published validator metadata: pubkey, IP+ports, version, timestamps. <a href="/module-5/1-gossip">Module 5.1</a></p><p><strong>Cooldown</strong> — stake state коли deactivating, чекає кінця epoch. <a href="/module-7/1-stake">Module 7.1</a></p><p><strong>CPI (Cross-Program Invocation)</strong> — програма викликає інше program у тому ж TX. <a href="/module-3/2-instructions">Module 3.2</a></p><p><strong>CPU governor</strong> — Linux setting що manages CPU frequency scaling. &quot;performance&quot; governor для validators. <a href="/module-8/6-kernel-tuning">Module 8.6</a></p><p><strong>Crates.io</strong> — public Rust package registry. <a href="/module-0/3-cargo">Module 0.3</a></p><h2 id="d" tabindex="-1">D <a class="header-anchor" href="#d" aria-label="Permalink to &quot;D&quot;">​</a></h2><p><strong>Daemon</strong> — background process відв&#39;язаний від terminal, managed by init system. <a href="/module-0/4-processes">Module 0.4</a></p><p><strong>Data shred</strong> — shred containing actual block content. <a href="/module-5/3-shreds">Module 5.3</a></p><p><strong>Debug build</strong> — non-optimized binary з debug symbols. Не для production. <a href="/module-0/1-build">Module 0.1</a></p><p><strong>Delegation (stake)</strong> — direct stake account до specific validator. One stake account → one validator. <a href="/module-7/1-stake">Module 7.1</a></p><p><strong>Delegator rewards</strong> — частка validator rewards до delegators proportional до їх stake. <a href="/module-7/2-rewards">Module 7.2</a></p><p><strong>Delinquent</strong> — validator status: не голосував &gt; 128 slots на rooted slot. Recoverable. <a href="/module-1/5-validator-status">Module 1.5</a></p><p><strong>Detached HEAD</strong> — git state коли HEAD вказує на commit/tag напряму, не на branch. <a href="/module-0/2-git">Module 0.2</a></p><p><strong>Devnet</strong> — Solana developer cluster. Free SOL з faucet, для testing apps. <a href="/module-1/1-cluster">Module 1.1</a></p><p><strong>Disaster recovery</strong> — procedure для restoring validator після catastrophic failure. <a href="/module-8/2-backups">Module 8.2</a></p><p><strong>Discriminator</strong> — first bytes of instruction data що identifies which method. Anchor uses 8-byte hash. <a href="/module-3/2-instructions">Module 3.2</a></p><p><strong>Disinflation</strong> — gradual reduction inflation rate. Solana: 15% yearly. <a href="/module-7/2-rewards">Module 7.2</a></p><p><strong>DoubleZero</strong> — dedicated low-latency network для Solana validator-to-validator traffic. <a href="/module-10/3-doublezero">Module 10.3</a></p><p><strong>Double-sign</strong> — validator signs two conflicting things (votes/blocks) at same slot. Slashable. <a href="/module-4/6-slashing-deep">Module 4.6</a></p><p><strong>Double-vote</strong> — see [Double-sign]. Specifically vote-level double signing. <a href="/module-4/2-tower-bft">Module 4.2</a></p><p><strong>DPDK</strong> — Data Plane Development Kit, kernel-bypass networking framework. Used by Firedancer + Fiber. <a href="/module-5/5-quic-fiber">Module 5.5</a></p><p><strong>Durable nonce</strong> — alternative до recent_blockhash для TX expiry. Long-lived. <a href="/module-3/6-durable-nonces">Module 3.6</a></p><p><strong>DWPD</strong> — Drive Writes Per Day. SSD endurance metric. Enterprise NVMe usually 3-10 DWPD. <a href="/module-8/5-hardware-specs">Module 8.5</a></p><p><strong>Dynamic linking</strong> — binary references shared <code>.so</code> libraries at runtime. <a href="/module-0/1-build">Module 0.1</a></p><h2 id="e" tabindex="-1">E <a class="header-anchor" href="#e" aria-label="Permalink to &quot;E&quot;">​</a></h2><p><strong>Entrypoint</strong> — well-known seed node для bootstrapping. <a href="/module-1/1-cluster">Module 1.1</a></p><p><strong>Environment variable</strong> — variable у shell environment. Accessed з <code>$VAR</code>. <a href="/module-0/6-shell">Module 0.6</a></p><p><strong>Epoch</strong> — 432,000 slots ≈ 48 годин mainnet. Group of slots з спільним leader schedule. <a href="/module-1/2-slots-epochs">Module 1.2</a></p><p><strong>Equinix</strong> — major datacenter operator (FR4 Frankfurt, AM3 Amsterdam, тощо). Validator co-location standard. <a href="/module-8/5-hardware-specs">Module 8.5</a></p><p><strong>Equivocation</strong> — leader signs two different blocks for same slot. Slashable. <a href="/module-4/6-slashing-deep">Module 4.6</a></p><p><strong>Erasure coding</strong> — Reed-Solomon redundancy: 32 data + 32 coding shreds, recover з будь-якими 32+. <a href="/module-5/3-shreds">Module 5.3</a></p><p><strong>Executable flag</strong> — account field: true для programs (call&#39;able), false для data. <a href="/module-2/1-account-basics">Module 2.1</a></p><h2 id="f" tabindex="-1">F <a class="header-anchor" href="#f" aria-label="Permalink to &quot;F&quot;">​</a></h2><p><strong>FEC set</strong> — group of shreds (typically 32 data + 32 coding) for Forward Error Correction. <a href="/module-5/3-shreds">Module 5.3</a></p><p><strong>Fee burn</strong> — 50% of TX fees permanently destroyed (deflationary). <a href="/module-3/3-fees">Module 3.3</a></p><p><strong>Fee payer</strong> — first signer у TX. Платить fees. <a href="/module-3/1-tx-anatomy">Module 3.1</a></p><p><strong>Feature activation</strong> — moment коли feature flag перейде з pending до active. Епоch-aligned. <a href="/module-4/7-recent-simds">Module 4.7</a></p><p><strong>Feature flag</strong> — pubkey identifying protocol feature. Code includes both old + new behavior gated by flag status. <a href="/module-4/7-recent-simds">Module 4.7</a></p><p><strong>Feature pubkey</strong> — identifier for specific feature. Status checked via <code>solana feature status</code>. <a href="/module-4/7-recent-simds">Module 4.7</a></p><p><strong>Fetch (git)</strong> — download нові commits/tags з remote. Не modify working tree. <a href="/module-0/2-git">Module 0.2</a></p><p><strong>Fiber</strong> — newer agave networking layer using kernel-bypass для high-performance turbine. <a href="/module-5/5-quic-fiber">Module 5.5</a></p><p><strong>Finalized (slot/TX)</strong> — vote depth 32 у tower. Cryptographic finality. ~12-30 sec mainnet. <a href="/module-3/4-lifecycle">Module 3.4</a></p><p><strong>fio</strong> — Linux disk I/O benchmark tool. Standard для validator hardware testing. <a href="/module-9/6-benchmarking">Module 9.6</a></p><p><strong>Firedancer</strong> — alternative validator client written у C by Jump Crypto. Performance + client diversity goal. <a href="/module-6/5-firedancer">Module 6.5</a></p><p><strong>Fork</strong> — situation коли cluster has two competing chains. <a href="/module-4/5-forks">Module 4.5</a></p><p><strong>Fork choice</strong> — algorithm для picking canonical fork. Heaviest stake-weighted wins. <a href="/module-4/5-forks">Module 4.5</a></p><p><strong>Frankendancer</strong> — hybrid agave + Firedancer components (transition phase). <a href="/module-6/5-firedancer">Module 6.5</a></p><p><strong>Freeze authority</strong> — wallet що може freeze token accounts. None = permissionless. <a href="/module-2/4-tokens-ata">Module 2.4</a></p><p><strong>Full snapshot</strong> — complete accountsDB state at slot. Mainnet ~80-100 GB. <a href="/module-10/2-snapshots">Module 10.2</a></p><h2 id="g" tabindex="-1">G <a class="header-anchor" href="#g" aria-label="Permalink to &quot;G&quot;">​</a></h2><p><strong>Garbage collection (accounts)</strong> — old system: accounts below rent threshold purged. <a href="/module-2/3-rent">Module 2.3</a></p><p><strong>Genesis</strong> — initial state cluster. All nodes мають однаковий genesis. <a href="/module-1/1-cluster">Module 1.1</a></p><p><strong>Genesis ceremony</strong> — coordinated process to launch new cluster з shared genesis file. <a href="/module-1/6-genesis">Module 1.6</a></p><p><strong>Genesis hash</strong> — unique fingerprint genesis. Identifies cluster. <a href="/module-1/1-cluster">Module 1.1</a></p><p><strong>Geyser</strong> — Solana plugin system для streaming live data з validator. <a href="/module-10/1-geyser-rpc">Module 10.1</a></p><p><strong>Glob</strong> — shell wildcard expansion (<code>*</code>, <code>?</code>, <code>[abc]</code>). Expanded by shell ДО execution. <a href="/module-0/6-shell">Module 0.6</a></p><p><strong>Gossip</strong> — epidemic protocol для propagating cluster membership + metadata. <a href="/module-5/1-gossip">Module 5.1</a></p><p><strong>Grafana</strong> — visualization tool для time-series data. Used з Prometheus для validator monitoring. <a href="/module-8/8-monitoring-stack">Module 8.8</a></p><h2 id="h" tabindex="-1">H <a class="header-anchor" href="#h" aria-label="Permalink to &quot;H&quot;">​</a></h2><p><strong>Halt threshold</strong> — % delinquent stake beyond which cluster halts. Mainnet 33%, Alpenglow ~18%. <a href="/module-1/5-validator-status">Module 1.5</a></p><p><strong>Hardlink</strong> — alternative filename для того ж inode. <a href="/module-0/5-filesystem">Module 0.5</a></p><p><strong>HEAD (git)</strong> — pointer &quot;де ти зараз&quot; у repo. <a href="/module-0/2-git">Module 0.2</a></p><p><strong>Heaviest fork rule</strong> — Solana fork choice: canonical fork = з найбільшим stake voting. <a href="/module-4/5-forks">Module 4.5</a></p><p><strong>Helius</strong> — popular Solana RPC provider з Geyser-enhanced services + cNFT indexing. <a href="/module-10/1-geyser-rpc">Module 10.1</a></p><p><strong>Heredoc</strong> — shell construct для multi-line input. <code>&lt;&lt;EOF ... EOF</code>. <a href="/module-0/6-shell">Module 0.6</a></p><p><strong>Hot key</strong> — key used continuously by software, on server. <a href="/module-8/1-keypair-security">Module 8.1</a></p><p><strong>Hugepages</strong> — large memory pages (2MB/1GB) для efficient buffering. Used by Firedancer + Fiber. <a href="/module-5/5-quic-fiber">Module 5.5</a></p><p><strong>Hyper-V</strong> — Microsoft virtualization platform. Backs WSL2. <a href="/module-0/9-wsl-windows">Module 0.9</a></p><h2 id="i" tabindex="-1">I <a class="header-anchor" href="#i" aria-label="Permalink to &quot;I&quot;">​</a></h2><p><strong>Identity rotation</strong> — replacing validator identity key. Via <code>agave-validator set-identity</code>. Use carefully avoid double-sign. <a href="/module-4/6-slashing-deep">Module 4.6</a></p><p><strong>Incident response</strong> — structured handling of operational alerts. Ack → assess → mitigate → investigate → document. <a href="/module-8/9-oncall-runbooks">Module 8.9</a></p><p><strong>Incremental snapshot</strong> — delta from last full snapshot. Small (~1 GB), created every ~100 slots. <a href="/module-10/2-snapshots">Module 10.2</a></p><p><strong>In-genesis</strong> — validators included у cluster&#39;s initial genesis (vs out-of-genesis joining later). <a href="/module-1/6-genesis">Module 1.6</a></p><p><strong>Inflation pool</strong> — нові SOL minted per epoch, distributed до validators proportional до credits. <a href="/module-7/2-rewards">Module 7.2</a></p><p><strong>Inflation rate</strong> — annual % new SOL supply created. ~5% currently, disinflating. <a href="/module-7/2-rewards">Module 7.2</a></p><p><strong>Init system</strong> — first process boot Linux (PID 1). systemd = standard. <a href="/module-0/4-processes">Module 0.4</a></p><p><strong>Inode</strong> — internal filesystem structure з file metadata + pointer до data blocks. <a href="/module-0/5-filesystem">Module 0.5</a></p><p><strong>Instruction</strong> — atomic unit у TX. Specifies program, accounts, data. <a href="/module-3/1-tx-anatomy">Module 3.1</a></p><p><strong>invoke_signed</strong> — CPI mechanism whereby program &quot;signs&quot; як PDA через seeds. <a href="/module-2/5-pda-deep">Module 2.5</a></p><p><strong>IOPS</strong> — I/O Operations Per Second. Disk benchmark metric. Mainnet target &gt; 200k random 4k read. <a href="/module-9/6-benchmarking">Module 9.6</a></p><p><strong>iperf3</strong> — network bandwidth benchmark tool. <a href="/module-9/6-benchmarking">Module 9.6</a></p><h2 id="j" tabindex="-1">J <a class="header-anchor" href="#j" aria-label="Permalink to &quot;J&quot;">​</a></h2><p><strong>JIP (Jito Improvement Proposal)</strong> — Jito DAO governance proposal. <a href="/module-10/4-governance">Module 10.4</a></p><p><strong>Jito</strong> — major MEV infrastructure provider для Solana. <a href="/module-7/3-mev-jito">Module 7.3</a></p><p><strong>Jito-Solana</strong> — fork agave validator з MEV functionality. ~50% mainnet stake runs це. <a href="/module-7/3-mev-jito">Module 7.3</a></p><p><strong>JitoSOL</strong> — Jito&#39;s liquid staking token. <a href="/module-7/3-mev-jito">Module 7.3</a></p><p><strong>journald</strong> — systemd&#39;s logging system. Read через <code>journalctl</code>. <a href="/module-0/4-processes">Module 0.4</a></p><p><strong>JTO</strong> — Jito DAO governance token. Votes на JIPs. <a href="/module-10/4-governance">Module 10.4</a></p><p><strong>Jump Crypto</strong> — trading firm creating Firedancer. <a href="/module-6/5-firedancer">Module 6.5</a></p><h2 id="k" tabindex="-1">K <a class="header-anchor" href="#k" aria-label="Permalink to &quot;K&quot;">​</a></h2><p><strong>Kernel bypass</strong> — networking technique routing packets directly до user-space (skip kernel). Fiber + Firedancer use. <a href="/module-5/5-quic-fiber">Module 5.5</a></p><p><strong>Key rotation</strong> — periodic replacement keys. <a href="/module-8/2-backups">Module 8.2</a></p><h2 id="l" tabindex="-1">L <a class="header-anchor" href="#l" aria-label="Permalink to &quot;L&quot;">​</a></h2><p><strong>Lamport</strong> — найменша одиниця SOL. 1 SOL = 10^9 lamports. <a href="/module-2/1-account-basics">Module 2.1</a></p><p><strong>Lamport credits</strong> — Alpenglow epochCredits semantics: actual lamport reward earned (НЕ vote count). <a href="/module-4/4-alpenglow">Module 4.4</a></p><p><strong>Last vote</strong> — slot of validator&#39;s most recent vote. <a href="/module-1/5-validator-status">Module 1.5</a></p><p><strong>Layer (turbine)</strong> — tree level. Layer 1 receives від leader first. <a href="/module-5/2-turbine">Module 5.2</a></p><p><strong>Leader</strong> — validator що має ексклюзивне право створити block у specific slot. <a href="/module-1/3-leaders">Module 1.3</a></p><p><strong>Leader schedule</strong> — pre-computed мапа slot → validator pubkey для всього epoch. <a href="/module-1/3-leaders">Module 1.3</a></p><p><strong>Leader slot group</strong> — consecutive slots assigned одному leader (4 на mainnet). <a href="/module-1/3-leaders">Module 1.3</a></p><p><strong>Linker</strong> — частина build process що з&#39;єднує object files + libraries у final binary. <a href="/module-0/1-build">Module 0.1</a></p><p><strong>Liquid staking token (LST)</strong> — token representing staked SOL з liquidity. JitoSOL, mSOL. <a href="/module-7/4-sfdp-pools">Module 7.4</a></p><p><strong>Lockout</strong> — Tower BFT commitment: validator не голосує за конфліктуючий fork. Exponential: depth N = 2^N slots. <a href="/module-4/2-tower-bft">Module 4.2</a></p><h2 id="m" tabindex="-1">M <a class="header-anchor" href="#m" aria-label="Permalink to &quot;M&quot;">​</a></h2><p><strong>Mainnet-beta</strong> — Solana&#39;s production cluster. <a href="/module-1/1-cluster">Module 1.1</a></p><p><strong>Merge stake</strong> — combine two compatible stake accounts. <a href="/module-7/6-stake-split-merge">Module 7.6</a></p><p><strong>Merkle tree</strong> — binary tree з hash combinations. Used у state compression. <a href="/module-10/6-compression-nfts">Module 10.6</a></p><p><strong>Merkle proof</strong> — sequence hashes proving specific item belongs to Merkle tree root. <a href="/module-10/6-compression-nfts">Module 10.6</a></p><p><strong>MEV (Maximum Extractable Value)</strong> — profit з smart TX ordering у block. <a href="/module-7/3-mev-jito">Module 7.3</a></p><p><strong>Micro-lamport</strong> — 1/1,000,000 of lamport. Unit для priority fee bids. <a href="/module-3/3-fees">Module 3.3</a></p><p><strong>Mint</strong> — token type-defining account. Stores mint authority, supply, decimals. <a href="/module-2/4-tokens-ata">Module 2.4</a></p><p><strong>Mint authority</strong> — pubkey that може mint нові tokens. <a href="/module-2/4-tokens-ata">Module 2.4</a></p><p><strong>Mode (file permissions)</strong> — <code>rwxrwxrwx</code> bits для u/g/o. <a href="/module-0/5-filesystem">Module 0.5</a></p><p><strong>Monitoring</strong> — observability of system health. <a href="/module-8/3-monitoring">Module 8.3</a></p><p><strong>Multicast</strong> — sending data до multiple recipients. Turbine uses tree multicast. <a href="/module-5/2-turbine">Module 5.2</a></p><p><strong>Multisig</strong> — wallet вимагає N-of-M signatures. Squads = standard Solana implementation. <a href="/module-8/1-keypair-security">Module 8.1</a></p><h2 id="n" tabindex="-1">N <a class="header-anchor" href="#n" aria-label="Permalink to &quot;N&quot;">​</a></h2><p><strong>Native program</strong> — built into agave validator binary. System, Vote, Stake, BPF Loader. <a href="/module-2/2-programs">Module 2.2</a></p><p><strong>Network partition</strong> — cluster splits into halves через network failure. <a href="/module-4/5-forks">Module 4.5</a></p><p><strong>N-of-M</strong> — multisig threshold notation. 3-of-5 = need 3 signatures з 5 keys. <a href="/module-8/7-treasury-multisig">Module 8.7</a></p><p><strong>node_exporter</strong> — Prometheus exporter для Linux system metrics (CPU, RAM, disk, network). <a href="/module-8/8-monitoring-stack">Module 8.8</a></p><p><strong>Nonce account</strong> — on-chain account holding durable nonce value. <a href="/module-3/6-durable-nonces">Module 3.6</a></p><p><strong>Nonce authority</strong> — key controlling nonce account (can advance, withdraw). <a href="/module-3/6-durable-nonces">Module 3.6</a></p><p><strong>Non-transferable</strong> — Token-2022 extension making tokens soul-bound. <a href="/module-2/6-token-2022">Module 2.6</a></p><p><strong>NUMA</strong> — Non-Uniform Memory Access. Multi-socket server architecture. Pinning validator до one NUMA node для consistent performance. <a href="/module-8/6-kernel-tuning">Module 8.6</a></p><p><strong>NVMe</strong> — NVM Express. Modern fast SSD interface. Required для validator (random I/O performance). <a href="/module-8/5-hardware-specs">Module 8.5</a></p><h2 id="o" tabindex="-1">O <a class="header-anchor" href="#o" aria-label="Permalink to &quot;O&quot;">​</a></h2><p><strong>Object file</strong> — intermediate compile output (<code>.o</code> файли). <a href="/module-0/1-build">Module 0.1</a></p><p><strong>Off-curve point</strong> — pubkey not on ed25519 curve. PDAs are off-curve (no private key exists). <a href="/module-2/5-pda-deep">Module 2.5</a></p><p><strong>Offline signing</strong> — sign TX без internet connection (cold wallet pattern). Use durable nonces. <a href="/module-3/6-durable-nonces">Module 3.6</a></p><p><strong>Oracle</strong> — bridge від off-chain data до on-chain. Pyth, Switchboard. <a href="/module-10/7-oracles">Module 10.7</a></p><p><strong>Orphaned block</strong> — block on losing fork після resolution. TXs reverted. <a href="/module-4/5-forks">Module 4.5</a></p><p><strong>Out-of-genesis</strong> — validators joining cluster ПІСЛЯ initial genesis (LumLabs Alpenglow case). <a href="/module-1/6-genesis">Module 1.6</a></p><p><strong>Owner (account)</strong> — program який володіє правом modify account state. <strong>Не</strong> wallet owner. <a href="/module-2/1-account-basics">Module 2.1</a></p><h2 id="p" tabindex="-1">P <a class="header-anchor" href="#p" aria-label="Permalink to &quot;P&quot;">​</a></h2><p><strong>Pane (tmux)</strong> — split window section. <a href="/module-0/7-tmux">Module 0.7</a></p><p><strong>Path</strong> — file system location. Absolute (<code>/home/...</code>) або relative. <a href="/module-0/5-filesystem">Module 0.5</a></p><p><strong>PATH (env var)</strong> — colon-separated list of directories де shell searches для executables. <a href="/module-0/6-shell">Module 0.6</a></p><p><strong>PBFT (Practical Byzantine Fault Tolerance)</strong> — classical consensus algorithm. Tower BFT = PBFT + PoH variant. <a href="/module-4/2-tower-bft">Module 4.2</a></p><p><strong>PDA (Program Derived Address)</strong> — special pubkey derived deterministically з seeds + program ID. No private key. <a href="/module-2/5-pda-deep">Module 2.5</a></p><p><strong>Pending feature</strong> — feature flag scheduled to activate at specific future epoch. <a href="/module-4/7-recent-simds">Module 4.7</a></p><p><strong>Permanent delegate</strong> — Token-2022 extension. Mint authority can always move/burn tokens. <a href="/module-2/6-token-2022">Module 2.6</a></p><p><strong>Permission</strong> — access rights для file/directory: read (r), write (w), execute (x). <a href="/module-0/5-filesystem">Module 0.5</a></p><p><strong>PID (Process ID)</strong> — unique number identifying running process. <a href="/module-0/4-processes">Module 0.4</a></p><p><strong>Pipe</strong> — shell <code>|</code> connecting stdout одного command до stdin наступного. <a href="/module-0/6-shell">Module 0.6</a></p><p><strong>PoH (Proof of History)</strong> — cryptographic clock через recursive SHA-256 hashing. NOT consensus itself. <a href="/module-4/1-poh">Module 4.1</a></p><p><strong>PoH bottleneck</strong> — PoH single-threaded, requires high single-thread CPU performance. <a href="/module-8/5-hardware-specs">Module 8.5</a></p><p><strong>PoH leader</strong> — validator generating PoH sequence у its slot. <a href="/module-4/1-poh">Module 4.1</a></p><p><strong>PoH service</strong> — validator thread що continuously runs hashing loop. <a href="/module-6/4-stages">Module 6.4</a></p><p><strong>Port forwarding</strong> — SSH feature forwarding ports between local і remote. <a href="/module-0/8-ssh">Module 0.8</a></p><p><strong>Post-mortem</strong> — post-incident analysis document. <a href="/module-8/9-oncall-runbooks">Module 8.9</a></p><p><strong>Prefix key (tmux)</strong> — combo activating tmux command mode. Default: Ctrl+B. <a href="/module-0/7-tmux">Module 0.7</a></p><p><strong>Price feed</strong> — oracle data feed для specific market price. <a href="/module-10/7-oracles">Module 10.7</a></p><p><strong>Priority fee</strong> — optional pay-per-CU для leader prioritization у congestion. <a href="/module-3/3-fees">Module 3.3</a></p><p><strong>Private key</strong> — secret half asymmetric keypair. Never share. <a href="/module-0/8-ssh">Module 0.8</a></p><p><strong>Process</strong> — running program у memory. <a href="/module-0/4-processes">Module 0.4</a></p><p><strong>Processed (slot/TX)</strong> — validator&#39;s local view: TX received and executed. <a href="/module-3/4-lifecycle">Module 3.4</a></p><p><strong>Program ID</strong> — pubkey of executable program account. <a href="/module-2/2-programs">Module 2.2</a></p><p><strong>Prometheus</strong> — time-series database + scraper для metrics. Standard validator monitoring. <a href="/module-8/8-monitoring-stack">Module 8.8</a></p><p><strong>ProxyJump</strong> — SSH feature для tunneling через bastion host. <a href="/module-0/8-ssh">Module 0.8</a></p><p><strong>Pubkey</strong> — 32-byte public key identifying account. Base58 encoded. <a href="/module-2/1-account-basics">Module 2.1</a></p><p><strong>Public key</strong> — public half asymmetric keypair. Safe to share. <a href="/module-0/8-ssh">Module 0.8</a></p><p><strong>Public snapshot</strong> — HTTP-accessible snapshot mirror для community catch-up. <a href="/module-10/5-snapshot-mirror">Module 10.5</a></p><p><strong>Pull dashboard</strong> — external service polls validator API для monitoring. <a href="/module-8/3-monitoring">Module 8.3</a></p><p><strong>Push alert</strong> — validator-side bot sends notifications. <a href="/module-8/3-monitoring">Module 8.3</a></p><p><strong>Pyth</strong> — institutional financial data oracle. First-party publishers, sub-second latency. <a href="/module-10/7-oracles">Module 10.7</a></p><h2 id="q" tabindex="-1">Q <a class="header-anchor" href="#q" aria-label="Permalink to &quot;Q&quot;">​</a></h2><p><strong>QUIC</strong> — modern transport protocol (UDP-based з reliability). Solana TPU uses. <a href="/module-5/5-quic-fiber">Module 5.5</a></p><h2 id="r" tabindex="-1">R <a class="header-anchor" href="#r" aria-label="Permalink to &quot;R&quot;">​</a></h2><p><strong>Realms</strong> — Solana governance framework. JTO voting на JIPs. <a href="/module-10/4-governance">Module 10.4</a></p><p><strong>Recent blockhash</strong> — hash recent block included у TX для expiry tracking. <a href="/module-3/1-tx-anatomy">Module 3.1</a></p><p><strong>Redirect</strong> — shell I/O redirection: <code>&gt;</code> (stdout), <code>2&gt;&amp;1</code> (stderr → stdout). <a href="/module-0/6-shell">Module 0.6</a></p><p><strong>Reed-Solomon</strong> — erasure coding algorithm. Solana shreds use. <a href="/module-5/3-shreds">Module 5.3</a></p><p><strong>Regional BE</strong> — geographically-distributed Jito Block Engines (Frankfurt, NY, Tokyo, etc.). <a href="/module-7/5-jito-block-engine">Module 7.5</a></p><p><strong>Release build</strong> — optimized binary для production. <code>cargo build --release</code>. <a href="/module-0/1-build">Module 0.1</a></p><p><strong>Reorg</strong> — cluster reorganizes around different fork. Дуже rare на Solana. <a href="/module-4/5-forks">Module 4.5</a></p><p><strong>Repair</strong> — protocol для requesting missing shreds/slots від peers. <a href="/module-5/4-repair">Module 5.4</a></p><p><strong>Replay stage</strong> — validator component що executes TXs у received block. <a href="/module-6/2-tvu">Module 6.2</a></p><p><strong>Repository (git)</strong> — directory з versioned code + history. <a href="/module-0/2-git">Module 0.2</a></p><p><strong>Rent</strong> — economic mechanism для storage costs. Current: rent-exempt threshold. <a href="/module-2/3-rent">Module 2.3</a></p><p><strong>Rent-exempt</strong> — account має ≥ threshold lamports щоб never need to pay rent. <a href="/module-2/3-rent">Module 2.3</a></p><p><strong>Rent reserve</strong> — lamports locked у account для rent-exempt. Returned at close. <a href="/module-2/3-rent">Module 2.3</a></p><p><strong>Rollback</strong> — revert до previous version (after failed upgrade). <a href="/module-8/4-upgrade-safety">Module 8.4</a></p><p><strong>Root slot</strong> — validator&#39;s highest finalized slot. <a href="/module-1/5-validator-status">Module 1.5</a></p><p><strong>Rooted slot</strong> — slot reached depth 32 у tower (lockout ~forever). <a href="/module-4/2-tower-bft">Module 4.2</a></p><p><strong>RPC node</strong> — full node з RPC enabled, не voting. <a href="/module-1/1-cluster">Module 1.1</a></p><p><strong>Runbook</strong> — pre-written step-by-step procedure для common incidents. <a href="/module-8/9-oncall-runbooks">Module 8.9</a></p><h2 id="s" tabindex="-1">S <a class="header-anchor" href="#s" aria-label="Permalink to &quot;S&quot;">​</a></h2><p><strong>scp</strong> — secure copy через SSH. <a href="/module-0/8-ssh">Module 0.8</a></p><p><strong>Searcher</strong> — algorithmic trader looking для MEV opportunities. Submits bundles до Jito. <a href="/module-7/3-mev-jito">Module 7.3</a></p><p><strong>Sealevel</strong> — Solana runtime для parallel TX execution. <a href="/module-3/2-instructions">Module 3.2</a></p><p><strong>Seeds (PDA)</strong> — input bytes для PDA derivation. Determines uniqueness. <a href="/module-2/5-pda-deep">Module 2.5</a></p><p><strong>Self-stake</strong> — validator operator stakes own SOL до own validator. <a href="/module-7/1-stake">Module 7.1</a></p><p><strong>SEV (severity)</strong> — incident classification: critical, warning, info. <a href="/module-8/9-oncall-runbooks">Module 8.9</a></p><p><strong>SFDP (Solana Foundation Delegation Program)</strong> — Foundation delegates stake до qualifying validators free. <a href="/module-7/4-sfdp-pools">Module 7.4</a></p><p><strong>SHA-256</strong> — cryptographic hash function. Used у PoH. <a href="/module-4/1-poh">Module 4.1</a></p><p><strong>Shell</strong> — command interpreter (bash, zsh). <a href="/module-0/6-shell">Module 0.6</a></p><p><strong>Shred</strong> — block fragment, 1280 bytes. Block split into ~64 shreds. <a href="/module-5/3-shreds">Module 5.3</a></p><p><strong>Shred publisher</strong> — DoubleZero role: validator що broadcasts shreds через DZ. <a href="/module-10/3-doublezero">Module 10.3</a></p><p><strong>Shred version</strong> — cluster identifier (related до genesis). <a href="/module-5/1-gossip">Module 5.1</a></p><p><strong>SIGHUP</strong> — Linux signal sent process коли controlling terminal closes. <a href="/module-0/4-processes">Module 0.4</a></p><p><strong>Signature aggregation</strong> — combining many signers&#39; signatures into one (BLS scheme). <a href="/module-4/4-alpenglow">Module 4.4</a></p><p><strong>Signature (TX)</strong> — 64-byte Ed25519 signature над TX message. <a href="/module-3/1-tx-anatomy">Module 3.1</a></p><p><strong>Signer</strong> — account marked as requiring signature у instruction. <a href="/module-3/1-tx-anatomy">Module 3.1</a></p><p><strong>Sigverify</strong> — TPU stage що verifies signatures. GPU-accelerated якщо є GPU. <a href="/module-6/1-tpu">Module 6.1</a></p><p><strong>SIMD (Solana Improvement Document)</strong> — Solana Foundation governance proposal. <a href="/module-10/4-governance">Module 10.4</a></p><p><strong>SIMD repo</strong> — github.com/solana-foundation/solana-improvement-documents. Все SIMD proposals. <a href="/module-4/7-recent-simds">Module 4.7</a></p><p><strong>Skip rate</strong> — % validator&#39;s leader slots що стали skipped. Health metric. Mainnet target &lt; 5%. <a href="/module-1/3-leaders">Module 1.3</a></p><p><strong>Skipped slot</strong> — slot з 0 blocks produced. <a href="/module-1/2-slots-epochs">Module 1.2</a></p><p><strong>Slashing</strong> — penalty (stake reduction) для malicious behavior. <a href="/module-4/2-tower-bft">Module 4.2</a></p><p><strong>Slashing condition</strong> — protocol-defined violation triggering slashing. <a href="/module-4/6-slashing-deep">Module 4.6</a></p><p><strong>Slot</strong> — 400ms time window. One leader per slot. <a href="/module-1/2-slots-epochs">Module 1.2</a></p><p><strong>Snapshot</strong> — compressed accountsDB state dump at slot. <a href="/module-5/4-repair">Module 5.4</a> / <a href="/module-10/2-snapshots">Module 10.2</a></p><p><strong>Snapshot mirror</strong> — HTTP server serving public snapshots для community. <a href="/module-10/5-snapshot-mirror">Module 10.5</a></p><p><strong>solana-bench-tps</strong> — Solana CLI tool для measuring cluster TX throughput. <a href="/module-9/6-benchmarking">Module 9.6</a></p><p><strong>solana-genesis</strong> — Solana CLI tool для creating new cluster genesis. <a href="/module-1/6-genesis">Module 1.6</a></p><p><strong>Source code</strong> — text written by human, before compilation. <a href="/module-0/1-build">Module 0.1</a></p><p><strong>SPL Token</strong> — standard token program на Solana (legacy). <a href="/module-2/4-tokens-ata">Module 2.4</a></p><p><strong>Split stake</strong> — divide stake account into two. <a href="/module-7/6-stake-split-merge">Module 7.6</a></p><p><strong>Squads</strong> — popular Solana multisig wallet. Industry standard для org treasuries. <a href="/module-8/7-treasury-multisig">Module 8.7</a></p><p><strong>ssh-agent</strong> — utility holding decrypted SSH keys у memory. <a href="/module-0/8-ssh">Module 0.8</a></p><p><strong>Stake account</strong> — account з owner = Stake Program, stores SOL для delegation. <a href="/module-7/1-stake">Module 7.1</a></p><p><strong>Stake activation</strong> — process whereby new delegation становить active. Epoch-aligned. <a href="/module-1/2-slots-epochs">Module 1.2</a></p><p><strong>Staker authority</strong> — key permitting delegate/redelegate stake. <a href="/module-7/1-stake">Module 7.1</a></p><p><strong>Stake pool</strong> — smart contract collecting retail SOL і delegating до validators. JitoSOL, Marinade. <a href="/module-7/4-sfdp-pools">Module 7.4</a></p><p><strong>Stake redelegation</strong> — change stake delegation від one validator до another. Needs deactivation + reactivation. <a href="/module-7/6-stake-split-merge">Module 7.6</a></p><p><strong>Stake snapshot</strong> — frozen state stakes at epoch boundary. Used для leader schedule. <a href="/module-1/3-leaders">Module 1.3</a></p><p><strong>Stake state</strong> — stake account current phase: Initialized, Activating, Active, Deactivating, Inactive. <a href="/module-7/1-stake">Module 7.1</a></p><p><strong>Stake-weighted QUIC</strong> — TPU prioritization для known stake-holders, anti-spam. <a href="/module-5/5-quic-fiber">Module 5.5</a></p><p><strong>Stake-weighted vote</strong> — voting power proportional до stake amount. <a href="/module-10/4-governance">Module 10.4</a></p><p><strong>StakeNet</strong> — Solana system для governing stake pool delegations через Steward Config. <a href="/module-7/4-sfdp-pools">Module 7.4</a></p><p><strong>State compression</strong> — Solana technique storing data у Merkle trees замість individual accounts. <a href="/module-10/6-compression-nfts">Module 10.6</a></p><p><strong>Stash (git)</strong> — temporarily set aside uncommitted changes. <a href="/module-0/2-git">Module 0.2</a></p><p><strong>Static linking</strong> — compiler embeds libraries inside binary. <a href="/module-0/1-build">Module 0.1</a></p><p><strong>Steward Config</strong> — StakeNet on-chain config defining stake pool validator selection criteria. NOT same as JIP-31/37. <a href="/module-7/4-sfdp-pools">Module 7.4</a></p><p><strong>Switchboard</strong> — general-purpose decentralized oracle. <a href="/module-10/7-oracles">Module 10.7</a></p><p><strong>Symlink</strong> — symbolic link, file containing path до another file. <a href="/module-0/5-filesystem">Module 0.5</a></p><p><strong>Symlink swap</strong> — rename symlink point до new target. Atomic version switch. <a href="/module-8/4-upgrade-safety">Module 8.4</a></p><p><strong>sysbench</strong> — multi-purpose Linux benchmark tool (CPU, memory, threads). <a href="/module-9/6-benchmarking">Module 9.6</a></p><p><strong>sysctl</strong> — Linux kernel runtime parameter tuning. Critical для validator (UDP buffers, swap, file descriptors). <a href="/module-8/6-kernel-tuning">Module 8.6</a></p><p><strong>System Program</strong> — native program (11111...) для basic SOL operations. <a href="/module-2/1-account-basics">Module 2.1</a></p><p><strong>systemd</strong> — modern Linux init system. Manages daemons (services). <a href="/module-0/4-processes">Module 0.4</a></p><h2 id="t" tabindex="-1">T <a class="header-anchor" href="#t" aria-label="Permalink to &quot;T&quot;">​</a></h2><p><strong>Tag (git)</strong> — immutable pointer до specific commit. <a href="/module-0/2-git">Module 0.2</a></p><p><strong>target/ directory</strong> — cargo build output directory. <a href="/module-0/1-build">Module 0.1</a></p><p><strong>Testnet</strong> — Solana pre-production cluster. <a href="/module-1/1-cluster">Module 1.1</a></p><p><strong>Threshold signing</strong> — multisig requires N-of-M signatures. <a href="/module-8/7-treasury-multisig">Module 8.7</a></p><p><strong>THP (Transparent Huge Pages)</strong> — Linux feature що may cause latency spikes. Disable для validators. <a href="/module-8/6-kernel-tuning">Module 8.6</a></p><p><strong>Tick (PoH)</strong> — basic time unit у PoH. ~64/sec mainnet. <a href="/module-4/1-poh">Module 4.1</a></p><p><strong>Tip account</strong> — special PDA holding Jito tip payments. <a href="/module-7/5-jito-block-engine">Module 7.5</a></p><p><strong>Tip distribution</strong> — Jito mechanism splitting tips operator vs stakers. <a href="/module-7/5-jito-block-engine">Module 7.5</a></p><p><strong>tmpfs</strong> — RAM-backed filesystem. Used для Alpenglow accountsDB. <a href="/module-6/3-accountsdb">Module 6.3</a></p><p><strong>tmux</strong> — terminal multiplexer. Persistent sessions surviving SSH disconnect. <a href="/module-0/7-tmux">Module 0.7</a></p><p><strong>Token account</strong> — SPL Token account holding balance. Owned by SPL Token Program. <a href="/module-2/4-tokens-ata">Module 2.4</a></p><p><strong>Token-2022</strong> — newer SPL token standard з extensions support. <a href="/module-2/6-token-2022">Module 2.6</a></p><p><strong>Token extensions</strong> — Token-2022 opt-in features per token. <a href="/module-2/6-token-2022">Module 2.6</a></p><p><strong>Tower</strong> — Tower BFT&#39;s per-validator vote stack (max 32 deep). <a href="/module-4/2-tower-bft">Module 4.2</a></p><p><strong>Tower BFT</strong> — Solana&#39;s current mainnet consensus algorithm. PBFT + PoH variant. <a href="/module-4/2-tower-bft">Module 4.2</a></p><p><strong>Tower file</strong> — validator&#39;s local tower (vote history) у <code>~/.solana/tower-N.bin</code>. Delete before restore avoid double-sign. <a href="/module-4/6-slashing-deep">Module 4.6</a></p><p><strong>TPU (Transaction Processing Unit)</strong> — validator&#39;s incoming TX path. <a href="/module-6/1-tpu">Module 6.1</a></p><p><strong>Transaction (TX)</strong> — atomic unit of execution. Max 1232 bytes. <a href="/module-3/1-tx-anatomy">Module 3.1</a></p><p><strong>Transfer fees</strong> — Token-2022 extension taking % per transfer. <a href="/module-2/6-token-2022">Module 2.6</a></p><p><strong>Transfer hooks</strong> — Token-2022 extension running custom program per transfer. <a href="/module-2/6-token-2022">Module 2.6</a></p><p><strong>Transient stake</strong> — stake у activating/deactivating state. Restricts split/merge. <a href="/module-7/6-stake-split-merge">Module 7.6</a></p><p><strong>Triton One</strong> — major Solana RPC provider, low-latency focus. Yellowstone Geyser framework. <a href="/module-10/1-geyser-rpc">Module 10.1</a></p><p><strong>TSDB</strong> — Time-Series Database. Prometheus uses TSDB для metrics storage. <a href="/module-8/8-monitoring-stack">Module 8.8</a></p><p><strong>Tunnel (DZ)</strong> — DoubleZero virtual tunnel між validator і DZ network. <a href="/module-10/3-doublezero">Module 10.3</a></p><p><strong>Turbine</strong> — Solana&#39;s block propagation protocol. Hierarchical tree multicast. <a href="/module-5/2-turbine">Module 5.2</a></p><p><strong>Turbine tree</strong> — per-slot dynamically built tree для shred distribution. <a href="/module-5/2-turbine">Module 5.2</a></p><p><strong>TVU (Transaction Validation Unit)</strong> — validator&#39;s incoming blocks path. <a href="/module-6/2-tvu">Module 6.2</a></p><p><strong>TX forwarding</strong> — non-leader validator forwards received TXs до current/upcoming leaders. <a href="/module-6/1-tpu">Module 6.1</a></p><h2 id="u" tabindex="-1">U <a class="header-anchor" href="#u" aria-label="Permalink to &quot;U&quot;">​</a></h2><p><strong>ulimits</strong> — per-user resource limits (file descriptors, processes). Critical для validator. <a href="/module-8/6-kernel-tuning">Module 8.6</a></p><p><strong>Unit file</strong> — systemd service config. <a href="/module-0/4-processes">Module 0.4</a></p><p><strong>Upgrade authority</strong> — key able to redeploy BPF program code. Set to None = immutable. <a href="/module-2/2-programs">Module 2.2</a></p><h2 id="v" tabindex="-1">V <a class="header-anchor" href="#v" aria-label="Permalink to &quot;V&quot;">​</a></h2><p><strong>Validator</strong> — node з vote account + stake що бере участь у consensus. <a href="/module-1/1-cluster">Module 1.1</a></p><p><strong>Validator Admission Ticket (VAT)</strong> — Alpenglow-specific: 1.6 SOL/epoch required для participation. <a href="/module-4/4-alpenglow">Module 4.4</a></p><p><strong>Validator rewards</strong> — operator income: inflation share + fees + Jito tips. <a href="/module-7/2-rewards">Module 7.2</a></p><p><strong>Vault account</strong> — Squads multisig PDA holding funds. <a href="/module-8/7-treasury-multisig">Module 8.7</a></p><p><strong>V0 transaction</strong> — Versioned transaction format (default since 2023). <a href="/module-3/5-versioned-tx-alts">Module 3.5</a></p><p><strong>Versioned transaction</strong> — TX format supporting ALTs. V0 currently. <a href="/module-3/5-versioned-tx-alts">Module 3.5</a></p><p><strong>Vote authority</strong> — key permitting sign vote TXs. Hot key on validator server. <a href="/module-4/3-votes-credits">Module 4.3</a></p><p><strong>Vote credit</strong> — Tower BFT: 1 per successful vote landed. Alpenglow: lamport reward. <a href="/module-4/3-votes-credits">Module 4.3</a></p><p><strong>VRF (Verifiable Random Function)</strong> — cryptographic randomness function. Used у leader schedule. <a href="/module-1/3-leaders">Module 1.3</a></p><p><strong>VRF (Switchboard)</strong> — verifiable random number service на Solana. <a href="/module-10/7-oracles">Module 10.7</a></p><h2 id="w" tabindex="-1">W <a class="header-anchor" href="#w" aria-label="Permalink to &quot;W&quot;">​</a></h2><p><strong>wait-for-restart-window</strong> — <code>agave-validator</code> subcommand blocking until safe to restart. <a href="/module-8/4-upgrade-safety">Module 8.4</a></p><p><strong>Warmup</strong> — stake state коли activating. <a href="/module-1/2-slots-epochs">Module 1.2</a></p><p><strong>Window (tmux)</strong> — full-screen terminal у tmux session. <a href="/module-0/7-tmux">Module 0.7</a></p><p><strong>Withdrawer authority</strong> — vote/stake account control key. <strong>Critical</strong>. Cold storage mandatory mainnet. <a href="/module-4/3-votes-credits">Module 4.3</a></p><p><strong>Working tree (git)</strong> — current files у repo на disk. <a href="/module-0/2-git">Module 0.2</a></p><p><strong>WSL</strong> — Windows Subsystem для Linux. WSL2 — full Linux kernel у Hyper-V VM. <a href="/module-0/9-wsl-windows">Module 0.9</a></p><h2 id="y" tabindex="-1">Y <a class="header-anchor" href="#y" aria-label="Permalink to &quot;Y&quot;">​</a></h2><p><strong>Yellowstone</strong> — Triton One&#39;s gRPC streaming framework для Geyser. <a href="/module-10/1-geyser-rpc">Module 10.1</a></p><h2 id="z" tabindex="-1">Z <a class="header-anchor" href="#z" aria-label="Permalink to &quot;Z&quot;">​</a></h2><p><strong>zstd</strong> — fast compression algorithm. Used для Solana snapshots. <a href="/module-10/2-snapshots">Module 10.2</a></p><hr><p><em>~230 terms. Updates з each module/section addition.</em></p>',363)])])}const m=o(s,[["render",n]]);export{c as __pageData,m as default};
